# Test with a simple node script that maintains SSE connection properly
node -e '
const http = require("http");

// Step 1: Connect to SSE
const sseReq = http.get("http://localhost:18101/sse", (res) => {
  let sessionUrl = "";
  res.on("data", (chunk) => {
    const text = chunk.toString();
    const match = text.match(/data: (\/message\?sessionId=[^\n]+)/);
    if (match && !sessionUrl) {
      sessionUrl = match[1];
      console.log("Got session:", sessionUrl);

      // Step 2: Send tools/list
      const listReq = http.request({
        hostname: "localhost",
        port: 18101,
        path: sessionUrl,
        method: "POST",
        headers: { "Content-Type": "application/json" }
      }, (listRes) => {
        console.log("tools/list status:", listRes.statusCode);
      });
      listReq.write(JSON.stringify({
        jsonrpc: "2.0",
        id: 1,
        method: "tools/list",
        params: {}
      }));
      listReq.end();

      // Step 3: Call the tool after a delay
      setTimeout(() => {
        const callReq = http.request({
          hostname: "localhost",
          port: 18101,
          path: sessionUrl,
          method: "POST",
          headers: { "Content-Type": "application/json" }
        }, (callRes) => {
          console.log("tool call status:", callRes.statusCode);
        });
        callReq.write(JSON.stringify({
          jsonrpc: "2.0",
          id: 2,
          method: "tools/call",
          params: {
            name: "read_url_content_as_markdown",
            arguments: { url: "https://httpbin.org/html" }
          }
        }));
        callReq.end();
      }, 1000);
    }

    // Print SSE events  
    if (text.includes("result")) {
      console.log("SSE response:", text.substring(0, 500));
    }
  });
});

setTimeout(() => { process.exit(0); }, 15000);
' 2>&1

# Test concurrent connections - two clients simultaneously
node -e '
const http = require("http");

function makeClient(name) {
  return new Promise((resolve, reject) => {
    const sseReq = http.get("http://localhost:18101/sse", (res) => {
      let sessionUrl = "";
      let resolved = false;
      res.on("data", (chunk) => {
        const text = chunk.toString();
        const match = text.match(/data: (\/message\?sessionId=[^\n]+)/);
        if (match && !sessionUrl) {
          sessionUrl = match[1];
          console.log(`[${name}] Connected: ${sessionUrl}`);

          setTimeout(() => {
            const callReq = http.request({
              hostname: "localhost", port: 18101,
              path: sessionUrl, method: "POST",
              headers: { "Content-Type": "application/json" }
            }, (r) => { console.log(`[${name}] POST status: ${r.statusCode}`); });
            callReq.write(JSON.stringify({
              jsonrpc: "2.0", id: 1,
              method: "tools/call",
              params: { name: "read_url_content_as_markdown", arguments: { url: "https://httpbin.org/html" } }
            }));
            callReq.end();
          }, 500);
        }
        if (text.includes('"result"') && text.includes('"content"') && !resolved) {
          resolved = true;
          const hasContent = text.includes("blacksmith") || text.includes("Perth");
          console.log(`[${name}] Got result: ${hasContent ? "SUCCESS" : "EMPTY"}`);
          resolve(hasContent);
        }
      });
    });
    setTimeout(() => { if (!resolved) { resolve(false); } }, 20000);
  });
}

Promise.all([makeClient("Client1"), makeClient("Client2")])
  .then(([r1, r2]) => {
    console.log(`\nConcurrent test: Client1=${r1}, Client2=${r2}`);
    console.log(r1 && r2 ? "PASS: Both clients succeeded" : "FAIL: At least one client failed");
    process.exit(0);
  });
' 2>&1

node -e '
const http = require("http");

function makeClient(name) {
  return new Promise((resolve) => {
    let resolved = false;
    const sseReq = http.get("http://localhost:18101/sse", (res) => {
      let sessionUrl = "";
      res.on("data", (chunk) => {
        const text = chunk.toString();
        const match = text.match(/data: (\/message\?sessionId=[^\n]+)/);
        if (match && !sessionUrl) {
          sessionUrl = match[1];
          console.log("[" + name + "] Connected: " + sessionUrl);

          setTimeout(() => {
            const callReq = http.request({
              hostname: "localhost", port: 18101,
              path: sessionUrl, method: "POST",
              headers: { "Content-Type": "application/json" }
            }, (r) => { console.log("[" + name + "] POST status: " + r.statusCode); });
            callReq.write(JSON.stringify({
              jsonrpc: "2.0", id: 1,
              method: "tools/call",
              params: { name: "read_url_content_as_markdown", arguments: { url: "https://httpbin.org/html" } }
            }));
            callReq.end();
          }, 500);
        }
        if (!resolved && text.includes("blacksmith")) {
          resolved = true;
          console.log("[" + name + "] Got result: SUCCESS");
          resolve(true);
        }
      });
    });
    setTimeout(() => { if (!resolved) { console.log("[" + name + "] TIMEOUT"); resolve(false); } }, 20000);
  });
}

Promise.all([makeClient("Client1"), makeClient("Client2")])
  .then(([r1, r2]) => {
    console.log("Concurrent test: Client1=" + r1 + ", Client2=" + r2);
    console.log(r1 && r2 ? "PASS: Both clients succeeded" : "FAIL");
    process.exit(0);
  });
' 2>&1

