#!/bin/bash
# Update ~/.claude.json by merging chezmoi template changes
# package.json hash: 2171938ad74ff1c93c3476259ca5d1d48077f8bde9f593de89bd1f74f295bce0
# hooks package.json hash: 882b776c191eef682f3d1d996c12f764e34dcbe48f508dac6f31a57a9db825d4
# mcp config hash: d76ff19f533acabfefb80ef963b560dddb1ad1e88c35cd67f916572246f63965
# script hash: 9233a03b1acb2f43119b200af7a51301db751a81bd234d56ab82c6cba8a21006

set -euo pipefail

TARGET_FILE="$HOME/.claude.json"
TEMP_FILE=$(mktemp)
BACKUP_FILE="${TARGET_FILE}.backup.$(date +%Y%m%d_%H%M%S)"
PACKAGE_JSON="/Users/berlysia/.local/share/chezmoi/package.json"
HOOKS_PACKAGE_JSON="/Users/berlysia/.local/share/chezmoi/home/dot_claude/package.json"

# Read versions from package.json (root or hook workspace)
READABILITY_VER=$(jq -r '.dependencies["@mizchi/readability"] // empty' "$HOOKS_PACKAGE_JSON")
CHROME_DEVTOOLS_VER=$(jq -r '.dependencies["chrome-devtools-mcp"] // empty' "$PACKAGE_JSON")
PLAYWRIGHT_VER=$(jq -r '.dependencies["@playwright/mcp"] // empty' "$PACKAGE_JSON")
CONTEXT7_VER=$(jq -r '.dependencies["@upstash/context7-mcp"] // empty' "$PACKAGE_JSON")
CODEX_VER=$(jq -r '.dependencies["@openai/codex"] // empty' "$PACKAGE_JSON")
DRAWIO_VER=$(jq -r '.dependencies["@drawio/mcp"] // empty' "$PACKAGE_JSON")

# Generate new content from versions
# MCP shared mode: true
TEMPLATE_CONTENT=$(cat << EOF
{
  "mcpServers": {
    "readability": {
      "type": "sse",
      "url": "http://localhost:18101/sse"
    },
    "context7": {
      "type": "sse",
      "url": "http://localhost:18102/sse"
    },
    "drawio": {
      "type": "sse",
      "url": "http://localhost:18103/sse"
    },
    "chrome-devtools": {
      "command": "pnpm",
      "args": ["dlx", "chrome-devtools-mcp@${CHROME_DEVTOOLS_VER}"]
    },
    "playwright": {
      "type": "stdio",
      "command": "pnpm",
      "args": ["dlx", "@playwright/mcp@${PLAYWRIGHT_VER}"],
      "env": {}
    },
    "codex": {
      "type": "stdio",
      "command": "pnpm",
      "args": ["dlx", "@openai/codex@${CODEX_VER}", "mcp-server"]
    }
  },
  "installMethod": "native",
  "preferredNotifChannel": "terminal_bell",
  "defaultMode": "allowEdits"
}

